import React, { useContext } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "../styles/Navbar.css";
import { ThemeContext } from "../context/Theme";

function Navbar() {
    const navigate = useNavigate();
    const { theme } = useContext(ThemeContext);

    const handleScrollToSection = (e, sectionId) => {
        e.preventDefault();
        navigate("/");
        setTimeout(() => {
            const section = document.getElementById(sectionId);
            if (section) {
                section.scrollIntoView({ behavior: "smooth" });
            }
        }, 100);
    };

    return (
        <nav className={`bubble-navbar ${theme}`}>
            <ul className="bubble-nav-list">
                <li>
                    <a href="/home" onClick={(e) => handleScrollToSection(e, "body-section")}>
                        Home
                    </a>
                </li>
                <li>
                    <a href="/body" onClick={(e) => handleScrollToSection(e, "body-section")}>
                        About Us
                    </a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>
                        Feedback
                    </a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>
                        Sign Language
                    </a>
                </li>
                <NavLink to="/signup">
                    <button className="bubble-signup-btn">Sign Up</button>
                </NavLink>
            </ul>
        </nav>
    );
}

export default Navbar;
